module RefModule(
    reset,
    clk,
    sel,
    in0,
    in1,
    in2,
    out);// Inputs
input reset;
input clk;
input [2:0] sel;
input in0;
input in1;
input in2;

// Outputs
output out;

reg out;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt) begin
    if (reset) begin
        out <= 1'b0;
    end else begin
        case (sel)
            3'b000: out <= in0;
            3'b001: out <= in1;
            3'b010: out <= in2;
            default: out <= 1'b0;
        endcase
    end
end

endmodule
